if (!Number.isFinite(userId)) {
  msg.statusCode = 400;
  msg.payload = { success: false, message: 'userId required' };
  return msg;
}
const readAt = Date.now();
msg.topic = "INSERT INTO user_notification_read (user_id, notification_id, read_at) SELECT ?, sub.id, ? FROM (SELECT id FROM charger_notifications ORDER BY created_at DESC LIMIT 1000) AS sub ON DUPLICATE KEY UPDATE read_at = VALUES(read_at)";
msg.payload = [userId, readAt];
return msg;

msg.payload = { success: true };
msg.statusCode = 200;
return msg;

const errMsg = msg.error && msg.error.message ? msg.error.message : (typeof msg.payload === 'string' ? msg.payload : 'Database or flow error');
const source = msg.error && msg.error.source ? msg.error.source : 'unknown';
msg.statusCode = 500;
msg.payload = { success: false, message: errMsg, _debug: { source } };
return msg;
